# --- Libre Franklin width measurement (renderer-independent fit) ---
def _load(fn):
    f=TTFont(os.path.join(FONTDIR,fn))
    return f['head'].unitsPerEm, f.getBestCmap(), f['hmtx']
_MET={400:_load("LibreFranklin-Regular.ttf"),700:_load("LibreFranklin-Bold.ttf")}
def natural_per_em(s,weight=400):
    upm,cmap,hmtx=_MET.get(weight,_MET[400]); w=0
    for ch in s:
        gid=cmap.get(ord(ch)) or cmap.get(ord(' '))
        w+=hmtx[gid][0]
    return w/upm
def fit_size(s,target_w,weight=400):
    pe=natural_per_em(s,weight)
    return target_w/pe if pe else 999
