def make_text(lineno, text, fill, anchor, cat_fs):
    weight = 700 if (BOLD and lineno in HEADINGS) else 400
    d=t.attr(lines[lineno-1],'d')
    x0,y0,x1,y1=t.bbox(d)
    target_w=x1-x0
    fs=min(cat_fs, fit_size(text,target_w,weight)*0.99)
    ax = (x0+x1)/2 if anchor=="middle" else x0
    base = y1 - (DESC*fs if has_desc(text) else 0) + YSHIFT
    esc=text.replace("&","&amp;").replace("<","&lt;").replace(">","&gt;")
    return (f'<text x="{ax:.2f}" y="{base:.2f}" fill="{fill}" '
            f'font-family="Libre Franklin" font-weight="{weight}" font-size="{fs:.2f}" '
            f'text-anchor="{anchor}" xml:space="preserve">{esc}</text>')

# ---------- arrows ----------
def chevron(tip, direction, L=HEAD_L, ang=HEAD_ANG):
    dx,dy=direction; n=math.hypot(dx,dy); ux,uy=dx/n,dy/n
    bx,by=-ux,-uy
    pts=[]
    for s in (+1,-1):
        a=math.radians(ang)*s
        rx=bx*math.cos(a)-by*math.sin(a)
        ry=bx*math.sin(a)+by*math.cos(a)
        pts.append((tip[0]+L*rx, tip[1]+L*ry))
    return pts

ASTYLE=f'stroke="#1E1E1E" stroke-width="{ARROW_W}" stroke-linecap="round" stroke-linejoin="round" fill="none"'

def arrow(tail, tip, dashed=False):
    p1,p2=chevron(tip,(tip[0]-tail[0],tip[1]-tail[1]))
    dash=' stroke-dasharray="6 5"' if dashed else ''
    line=f'<path d="M{tail[0]:.2f} {tail[1]:.2f}L{tip[0]:.2f} {tip[1]:.2f}" {ASTYLE}{dash}/>'
    head=f'<path d="M{p1[0]:.2f} {p1[1]:.2f}L{tip[0]:.2f} {tip[1]:.2f}L{p2[0]:.2f} {p2[1]:.2f}" {ASTYLE}/>'
    return line+"\n"+head

def bracket(source, junction_x, branch_ys, tip_x):
    """source->junction at source y; vertical spine spanning branch_ys; horizontals to tip_x with chevrons."""
    out=[]
    sy=source[1]
    out.append(f'<path d="M{source[0]:.2f} {sy:.2f}L{junction_x:.2f} {sy:.2f}" {ASTYLE}/>')
    ylo,yhi=min(branch_ys+[sy]),max(branch_ys+[sy])
    out.append(f'<path d="M{junction_x:.2f} {ylo:.2f}L{junction_x:.2f} {yhi:.2f}" {ASTYLE}/>')
    for by in branch_ys:
        out.append(f'<path d="M{junction_x:.2f} {by:.2f}L{tip_x:.2f} {by:.2f}" {ASTYLE}/>')
        p1,p2=chevron((tip_x,by),(1,0))
        out.append(f'<path d="M{p1[0]:.2f} {p1[1]:.2f}L{tip_x:.2f} {by:.2f}L{p2[0]:.2f} {p2[1]:.2f}" {ASTYLE}/>')
    return "\n".join(out)

